const BASE_URL = '/api/products';

export const getProducts = () => fetch(BASE_URL).then(r => r.json());

export const createProduct = (data, image) => {
  const formData = new FormData();
  Object.entries(data).forEach(([key, value]) => formData.append(key, value));
  if (image) formData.append('image', image);
  return fetch(BASE_URL, { method: 'POST', body: formData }).then(r => r.json());
};

export const deleteProduct = async (id) => {
  const res = await fetch(`${BASE_URL}/${id}`, { method: 'DELETE' });
  if (res.status === 204 || res.ok) return true;
  throw new Error(`Удаление не удалось: ${res.status}`);
};

export const updateProduct = (id, data, image)
